mapper.select:
select s.id, s.name, s.no, s.gender, s.phone, s.id_card, s.is_college, s.address, s.degree, s.graduation_date, s.clazz_id, s.violation_count, s.violation_score, s.create_time, s.update_time, c.name as clazz_name from student as s left join clazz as c on s.clazz_id = c.id
s.name like concat('%', #{name}, '%')
and s.degree = #{degree}
and s.clazz_id = #{clazzId}

mapper.update:
update student
set violation_count = violation_count + 1,
    violation_score = violation_score + #{score}
where id = #{id}
